import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { PatientService } from '../../services/patient.service';

@Component({
  selector: 'app-patient',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './patient.component.html',
  styleUrls: ['./patient.component.scss']
})
export class PatientComponent implements OnInit {
  searchId = '';
  patient: any = { gender: '' };
  patientList: any[] = [];
  filteredList: any[] = [];

  constructor(private patientService: PatientService) {}

  ngOnInit() {
    this.loadPatients();
  }

  loadPatients() {
    this.patientService.getAll().subscribe({
      next: (data) => {
        this.patientList = data;
        this.filteredList = [...data];
      },
      error: () => alert('Failed to load patients')
    });
  }

  search() {
    const term = this.searchId.toLowerCase().trim();
    if (term) {
      this.filteredList = this.patientList.filter(p => 
        p.id.toString().includes(term) ||
        p.firstName.toLowerCase().includes(term) ||
        p.lastName.toLowerCase().includes(term) ||
        (p.nic && p.nic.toLowerCase().includes(term))
      );
    } else {
      this.filteredList = [...this.patientList];
    }
  }

  save() {
    if (this.patient.firstName && this.patient.lastName) {
      this.patientService.add(this.patient).subscribe({
        next: (res) => {
          alert(res.message);
          this.resetForm();
          this.loadPatients();
        },
        error: (err) => alert(err.error?.message || 'Failed to add patient')
      });
    }
  }

  update() {
    this.patientService.update(this.patient.id, this.patient).subscribe({
      next: (res) => {
        alert(res.message);
        this.resetForm();
        this.loadPatients();
      },
      error: (err) => alert(err.error?.message || 'Failed to update patient')
    });
  }

  delete() {
    if (this.patient.id && confirm('Delete this patient?')) {
      this.patientService.delete(this.patient.id).subscribe({
        next: (res) => {
          alert(res.message);
          this.resetForm();
          this.loadPatients();
        },
        error: (err) => alert(err.error?.message || 'Failed to delete patient')
      });
    }
  }

  deleteFromTable(id: number) {
    if (confirm('Delete this patient?')) {
      this.patientService.delete(id).subscribe({
        next: () => this.loadPatients(),
        error: (err) => alert(err.error?.message || 'Failed to delete patient')
      });
    }
  }

  editPatient(p: any) {
    this.patient = { ...p };
  }

  generateReport() {
    console.table(this.patientList);
    alert('Report generated in Console!');
  }

  resetForm() {
    this.patient = { gender: '' };
    this.filteredList = [...this.patientList];
    this.searchId = '';
  }
}
